func getEnvOrDefault(key, defaultVal string) string {
	if val := os.Getenv(key); val != "" {
		return val
	}
	return defaultVal
}

// reflectionMethodPrefix is the gRPC reflection service method prefix.
const reflectionMethodPrefix = "/grpc.reflection."

// rateLimiter provides simple per-peer rate limiting for reflection calls.
type rateLimiter struct {
	counts map[string]*tokenBucket
}

type tokenBucket struct {
	tokens     int
	maxTokens  int
	lastRefill time.Time
	refillRate int // tokens per second
}

func newRateLimiter() *rateLimiter {
	return &rateLimiter{
		counts: make(map[string]*tokenBucket),
	}
}

func (rl *rateLimiter) allow(peerAddr string) bool {
	now := time.Now()
	bucket, exists := rl.counts[peerAddr]
	if !exists {
		bucket = &tokenBucket{
			tokens:     10,
			maxTokens:  10,
			lastRefill: now,
			refillRate: 2, // 2 requests per second
		}
		rl.counts[peerAddr] = bucket
	}

	// Refill tokens
	elapsed := now.Sub(bucket.lastRefill)
	newTokens := int(elapsed.Seconds()) * bucket.refillRate
	if newTokens > 0 {
		bucket.tokens += newTokens
		if bucket.tokens > bucket.maxTokens {
			bucket.tokens = bucket.maxTokens
		}
		bucket.lastRefill = now
	}

	if bucket.tokens > 0 {
		bucket.tokens--
		return true
	}
	return false
}

// authAndReflectionGuardInterceptor is a unary interceptor that:
