// authorizeReflection checks whether the caller is authorized to use the reflection API.
func authorizeReflection(ctx context.Context, cfg *Config, rl *rateLimiter) error {
	// Rate limiting
	peerAddr := getPeerAddress(ctx)
	if !rl.allow(peerAddr) {
		return status.Error(codes.ResourceExhausted, "reflection rate limit exceeded")
	}

	// In mTLS mode, check client certificate CN/SAN against ACL
	if p, ok := peer.FromContext(ctx); ok {
		if tlsInfo, ok := p.AuthInfo.(credentials.TLSInfo); ok {
			if len(tlsInfo.State.PeerCertificates) > 0 {
				clientCert := tlsInfo.State.PeerCertificates[0]
				return checkCertificateACL(clientCert, cfg.ReflectionACL)
			}
		}
	}

	// If no mTLS, check for authorization token in metadata
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return status.Error(codes.Unauthenticated, "no authentication credentials provided")
	}

	authHeaders := md.Get("authorization")
	if len(authHeaders) == 0 {
		return status.Error(codes.Unauthenticated, "authorization header required for reflection API")
	}

	// Validate the token - in production, use a proper token validation mechanism
	// (e.g., JWT verification, token introspection)
	token := strings.TrimPrefix(authHeaders[0], "Bearer ")
	if err := validateReflectionToken(token, cfg); err != nil {
		return status.Error(codes.PermissionDenied, "insufficient permissions for reflection API")
	}

	return nil
}

// checkCertificateACL verifies the client certificate against the allowed list.
func checkCertificateACL(cert *x509.Certificate, allowedIdentities []string) error {
	if len(allowedIdentities) == 0 {
		// If no ACL is configured, deny by default (fail-closed)
		return status.Error(codes.PermissionDenied, "reflection ACL not configured; access denied")
	}

	// Check Common Name
	for _, allowed := range allowedIdentities {
		if cert.Subject.CommonName == allowed {
			return nil
		}
	}

	// Check SANs (URIs for SPIFFE IDs)
	for _, uri := range cert.URIs {
		for _, allowed := range allowedIdentities {
			if uri.String() == allowed {
				return nil
			}
		}
	}

	// Check DNS SANs
	for _, dns := range cert.DNSNames {
		for _, allowed := range allowedIdentities {
			if dns == allowed {
				return nil
			}
		}
	}

	return status.Error(codes.PermissionDenied, "client certificate not in reflection ACL")
}

